  unsigned long long stop=clock64();
  cyc[0]=stop-start; out[0]=x;
}
__global__ void smid_kernel(int *seen){ unsigned smid; asm volatile("mov.u32 %0, %%smid;" : "=r"(smid)); if(smid<1024) atomicExch(&seen[smid],1); }
__global__ void scale_kernel(unsigned long long iters, float* out){ int tid=threadIdx.x + blockIdx.x*blockDim.x; float x=tid+1.0f; #pragma unroll 1 for(unsigned long long i=0;i<iters;i++) x = x * 1.0000001f + 0.000001f; out[tid]=x; }
int main(){
  unsigned long long *dcyc; float *dout; CHECK(cudaMalloc(&dcyc,sizeof(unsigned long long))); CHECK(cudaMalloc(&dout, 1<<20));
  cudaEvent_t ev_start, ev_stop; CHECK(cudaEventCreate(&ev_start)); CHECK(cudaEventCreate(&ev_stop));
  unsigned long long iters=500000000ULL; float best=0.0f; float sink=0;
  for(int t=0;t<5;t++){
    CHECK(cudaDeviceSynchronize()); CHECK(cudaEventRecord(ev_start)); burn_kernel<<<1,1>>>(iters,dcyc,dout); CHECK(cudaEventRecord(ev_stop)); CHECK(cudaEventSynchronize(ev_stop));
    float ms=0; CHECK(cudaEventElapsedTime(&ms,ev_start,ev_stop)); unsigned long long cyc; CHECK(cudaMemcpy(&cyc,dcyc,sizeof(unsigned long long),cudaMemcpyDeviceToHost)); CHECK(cudaMemcpy(&sink,dout,sizeof(float),cudaMemcpyDeviceToHost));
    float mhz = (float)cyc / (ms*1000.0f); if(mhz>best) best=mhz; printf("RESULT:boost_trial_%d_mhz=%.2f\n", t, mhz);
  }
  printf("RESULT:actual_boost_clock_mhz=%.2f\n", best);
  int *dseen; CHECK(cudaMalloc(&dseen,1024*sizeof(int))); CHECK(cudaMemset(dseen,0,1024*sizeof(int))); smid_kernel<<<4096,256>>>(dseen); CHECK(cudaDeviceSynchronize()); std::vector<int> seen(1024); CHECK(cudaMemcpy(seen.data(),dseen,1024*sizeof(int),cudaMemcpyDeviceToHost)); int cnt=0; for(int v:seen) if(v) cnt++; printf("RESULT:num_sms_ptx=%d\n", cnt);
  int threads=256; unsigned long long siters=2000000ULL; float *dscale; CHECK(cudaMalloc(&dscale, threads*512*sizeof(float))); std::vector<float> times; for(int blocks=1; blocks<=256; blocks++){ CHECK(cudaDeviceSynchronize()); CHECK(cudaEventRecord(ev_start)); scale_kernel<<<blocks,threads>>>(siters,dscale); CHECK(cudaEventRecord(ev_stop)); CHECK(cudaEventSynchronize(ev_stop)); float ms=0; CHECK(cudaEventElapsedTime(&ms,ev_start,ev_stop)); times.push_back(ms); printf("RESULT:scale_blocks_%d_ms=%.4f\n", blocks, ms); }
  float flat=times[0]; for(int i=0;i<20 && i<(int)times.size(); i++) flat = std::min(flat, times[i]); int knee=256; for(int i=0;i<(int)times.size(); i++){ if(times[i] > flat*1.10f){ knee=i+1; break; } } printf("RESULT:num_sms_throughput=%d\n", knee);
  fprintf(stderr, "sink=%f\n", sink);
  return 0;
}
"}

