__global__ void copy_kernel(const float4* __restrict__ src, float4* __restrict__ dst, size_t n){ size_t idx = blockIdx.x*blockDim.x + threadIdx.x; size_t stride = blockDim.x*gridDim.x; for(size_t i=idx;i<n;i+=stride) dst[i]=src[i]; }
int main(){
  const size_t bytes = 512ULL*1024*1024; const size_t n = bytes/sizeof(float4);
  float4 *src,*dst; CHECK(cudaMalloc(&src,bytes)); CHECK(cudaMalloc(&dst,bytes)); std::vector<float4> h(n); for(size_t i=0;i<n;i++){ h[i].x=i%13+1; h[i].y=i%17+2; h[i].z=i%19+3; h[i].w=i%23+4; } CHECK(cudaMemcpy(src,h.data(),bytes,cudaMemcpyHostToDevice));
  int threads=256; int blocks=4096; cudaEvent_t ev_start, ev_stop; CHECK(cudaEventCreate(&ev_start)); CHECK(cudaEventCreate(&ev_stop)); copy_kernel<<<blocks,threads>>>(src,dst,n); CHECK(cudaDeviceSynchronize());
  float best_ms=1e30f; for(int t=0;t<10;t++){ CHECK(cudaEventRecord(ev_start)); copy_kernel<<<blocks,threads>>>(src,dst,n); CHECK(cudaEventRecord(ev_stop)); CHECK(cudaEventSynchronize(ev_stop)); float ms=0; CHECK(cudaEventElapsedTime(&ms,ev_start,ev_stop)); if(ms<best_ms) best_ms=ms; printf("RESULT:copy_trial_%d_ms=%.4f\n", t, ms); }
  float gbps = (2.0*bytes)/(best_ms/1000.0)/1e9; printf("RESULT:peak_memory_bandwidth_gb_s=%.2f\n", gbps);
  std::vector<float4> out(4); CHECK(cudaMemcpy(out.data(),dst,4*sizeof(float4),cudaMemcpyDeviceToHost)); printf("RESULT:copy_sink=%f\n", out[0].x + out[1].y + out[2].z + out[3].w);
  return 0;
}
"}

